internal import Combine////  DashboardViewModel.swift//  FinanceApp////  Created by user271129 on 5/28/26.//import Foundation@MainActorfinal class DashboardViewModel: ObservableObject {    @Published var accounts: [Account] = []    @Published var selectedAccount: Account?    @Published var period: DashboardPeriod = .month    @Published var isExpense: Bool = true    @Published var categories: [CategorySummary] = []    @Published var totalBalance: Decimal = 0      // общий баланс по всем счетам (из статистики)    @Published var periodTotal: Decimal = 0       // сумма за период по фильтру (расход/доход)    @Published var allCategories: [Category] = []    func load() async {        do {                        await reloadData()        } catch {            print("Ошибка загрузки:", error)        }    }    func reloadData() async {        do {            let dtos = try await AccountService.shared.getAll()            accounts = dtos.map { $0.toModel() }            let catDtos = try await CategoryService.shared.getAll()            allCategories = catDtos.map { $0.toModel() }            totalBalance = try await StatisticsService.shared.getTotalBalance()            //selectedAccount = accounts.first        }        catch {print(error)}        let interval = period.dateInterval        do {            let txDtos: [TransactionDto]            if let account = selectedAccount {                txDtos = try await TransactionService.shared.getByAccount(                    id: account.id,                    from: interval.start,                    to: interval.end                )            } else {                txDtos = try await TransactionService.shared.getByPeriod(                    from: interval.start,                    to: interval.end                )            }            let tx = txDtos.map { $0.toModel() }            let filtered = tx.filter { $0.type == (isExpense ? .expense : .income) }                        periodTotal = filtered.reduce(0) { $0 + $1.amount }            let grouped = Dictionary(grouping: filtered, by: { $0.categoryId })            categories = grouped.compactMap { (categoryId, items) in                guard                    let categoryId,                    let category = allCategories.first(where: { $0.id == categoryId })                else { return nil }                return CategorySummary(                    category: category,                    total: items.reduce(0) { $0 + $1.amount }                )            }            .sorted { $0.total > $1.total }        } catch {            print("Ошибка транзакций:", error)        }    }}